import React, { createContext, useContext, useState, useCallback } from 'react';

const NotificationContext = createContext();

export const useNotification = () => {
    const context = useContext(NotificationContext);
    if (!context) {
        throw new Error('useNotification must be used within a NotificationProvider');
    }
    return context;
};

export const NotificationProvider = ({ children }) => {
    const [notifications, setNotifications] = useState([]);

    const removeNotification = useCallback((id) => {
        setNotifications((prev) => prev.filter((n) => n.id !== id));
    }, []);

    const showNotification = useCallback((message, type = 'info') => {
        const id = Math.random().toString(36).substr(2, 9);
        setNotifications((prev) => [...prev, { id, message, type }]);

        setTimeout(() => {
            removeNotification(id);
        }, 5000);
    }, [removeNotification]);

    const showSuccess = (msg) => showNotification(msg, 'success');
    const showError = (msg) => showNotification(msg, 'error');
    const showWarning = (msg) => showNotification(msg, 'warning');
    const showInfo = (msg) => showNotification(msg, 'info');

    return (
        <NotificationContext.Provider value={{ showSuccess, showError, showWarning, showInfo }}>
            {children}
            <div className="notification-container">
                {notifications.map((n) => (
                    <div key={n.id} className={`notification notification-${n.type}`}>
                        <div className="notification-content">
                            <span className="notification-icon">
                                {n.type === 'success' && <i className="fa-solid fa-circle-check"></i>}
                                {n.type === 'error' && <i className="fa-solid fa-circle-exclamation"></i>}
                                {n.type === 'warning' && <i className="fa-solid fa-triangle-exclamation"></i>}
                                {n.type === 'info' && <i className="fa-solid fa-circle-info"></i>}
                            </span>
                            <span className="notification-message">{n.message}</span>
                        </div>
                        <button className="notification-close" onClick={() => removeNotification(n.id)}>
                            <i className="fa-solid fa-xmark"></i>
                        </button>
                    </div>
                ))}
            </div>
        </NotificationContext.Provider>
    );
};
